24	/**
25	 * Normalize a relative path: forward slashes, no leading/trailing slash,
26	 * collapse repeated separators, reject ".." traversal.
27	 */
28	export function normalizeRelativePath(input: string): string {
29	  let p = input.replace(/\\/g, "/");
30	  p = p.replace(/\/+/g, "/");
31	  p = p.replace(/^\//, "").replace(/\/$/, "");
32	  p = p.trim();
33	  if (p.includes("..")) throw new Error("Path traversal (..) not allowed");
34	  return p;
35	}
