73	/**
74	 * Parse any supported input path and extract the canonical relative_path.
75	 * Supports: UNC (host/IP), container path, Synology Drive local path, already-relative.
76	 */
77	export function parseInputPath(
78	  input: string,
79	  config: NasConfig,
80	  userSyncRoot?: string | null
81	): ParseResult {
82	  const trimmed = input.trim();
83	  if (!trimmed) return { valid: false, relativePath: null, error: "Empty input" };
84	
85	  const shareLower = config.NAS_SHARE.toLowerCase();
86	
87	  try {
88	    // UNC path: \\host\share\...  or  \\ip\share\...
89	    if (trimmed.startsWith("\\\\")) {
90	      const parts = trimmed.replace(/\\\\/g, "").split("\\").filter(Boolean);
91	      if (parts.length < 2) return { valid: false, relativePath: null, error: "Invalid UNC path" };
92	      const hostOrIp = parts[0];
93	      const share = parts[1];
94	      if (share.toLowerCase() !== shareLower) {
95	        return { valid: false, relativePath: null, error: `PATH_OUT_OF_SCOPE: path is not inside configured NAS share '${config.NAS_SHARE}'` };
96	      }
97	      const rel = normalizeRelativePath(parts.slice(2).join("/"));
98	      return {
99	        valid: true,
100	        relativePath: rel,
101	        displays: getPathDisplayModes(rel, config, userSyncRoot),
102	      };
103	    }
104	
105	    // Container path: /mnt/nas/mac/...
106	    if (config.NAS_CONTAINER_MOUNT_ROOT) {
107	      const mountRoot = config.NAS_CONTAINER_MOUNT_ROOT.replace(/\/$/, "");
108	      if (trimmed.startsWith(mountRoot + "/") || trimmed === mountRoot) {
109	        const after = trimmed.slice(mountRoot.length);
110	        const rel = normalizeRelativePath(after);
111	        return {
112	          valid: true,
113	          relativePath: rel,
114	          displays: getPathDisplayModes(rel, config, userSyncRoot),
115	        };
116	      }
117	    }
118	
119	    // Synology Drive local path
120	    if (userSyncRoot) {
121	      const syncNorm = userSyncRoot.replace(/\\/g, "/").replace(/\/$/, "").toLowerCase();
122	      const inputNorm = trimmed.replace(/\\/g, "/").toLowerCase();
123	      if (inputNorm.startsWith(syncNorm + "/")) {
124	        const after = trimmed.replace(/\\/g, "/").slice(syncNorm.length + 1);
125	        // Strip share prefix if present
126	        const afterParts = after.split("/");
127	        if (afterParts[0]?.toLowerCase() === shareLower) {
128	          const rel = normalizeRelativePath(afterParts.slice(1).join("/"));
129	          return {
130	            valid: true,
131	            relativePath: rel,
132	            displays: getPathDisplayModes(rel, config, userSyncRoot),
133	          };
134	        }
135	        return { valid: false, relativePath: null, error: `PATH_OUT_OF_SCOPE: share '${config.NAS_SHARE}' not found after sync root` };
136	      }
137	    }
138	
139	    // Check if it contains share name somewhere (generic POSIX path with share)
140	    const posixInput = trimmed.replace(/\\/g, "/");
141	    const posixParts = posixInput.split("/").filter(Boolean);
142	    const shareIdx = posixParts.findIndex(p => p.toLowerCase() === shareLower);
143	    if (shareIdx >= 0 && shareIdx < posixParts.length - 1) {
144	      const rel = normalizeRelativePath(posixParts.slice(shareIdx + 1).join("/"));
145	      return {
146	        valid: true,
147	        relativePath: rel,
148	        displays: getPathDisplayModes(rel, config, userSyncRoot),
149	      };
150	    }
151	
152	    // Already relative (no share prefix needed)
153	    if (!trimmed.startsWith("/") && !trimmed.startsWith("\\") && !trimmed.includes(":")) {
154	      const rel = normalizeRelativePath(trimmed);
155	      return {
156	        valid: true,
157	        relativePath: rel,
158	        displays: getPathDisplayModes(rel, config, userSyncRoot),
159	      };
160	    }
161	
162	    return { valid: false, relativePath: null, error: "Could not parse path format" };
163	  } catch (e) {
164	    return { valid: false, relativePath: null, error: e instanceof Error ? e.message : "Parse error" };
165	  }
166	}
